import { createGame, createSudoku } from '../../../domain/index.js';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
const EMPTY_GRID = Array.from({ length: 9 }, () => Array(9).fill(0));

function cloneGrid(board) {
	return board.map((row) => row.slice());
}

function createDomainGameStore() {
	const state = writable({
		puzzleGrid: cloneGrid(EMPTY_GRID),
		game: createGame({ sudoku: createSudoku(EMPTY_GRID) }),
		solvedGrid: cloneGrid(EMPTY_GRID),
	});

	const syncFromPuzzle = (puzzleGrid) => {
		state.set({
			puzzleGrid: cloneGrid(puzzleGrid),
			game: createGame({ sudoku: createSudoku(puzzleGrid) }),
			solvedGrid: solveSudoku(puzzleGrid),
		});
	};

	const applyGuess = (row, col, value) => {
		state.update(($state) => {
			if (row == null || col == null) return $state;
			if ($state.puzzleGrid[row][col] !== 0) return $state;
			$state.game.guess({ row, col, value });
			return { ...$state };
		});
	};

	return {
		subscribe: state.subscribe,
		generate(difficulty) {
			syncFromPuzzle(generateSudoku(difficulty));
		},
		decodeSencode(sencode) {
			syncFromPuzzle(decodeSencode(sencode));
		},
		guess(row, col, value) {
			applyGuess(row, col, value);
		},
		undo() {
			state.update(($state) => {
				$state.game.undo();
				return { ...$state };
			});
		},
		redo() {
			state.update(($state) => {
				$state.game.redo();
				return { ...$state };
			});
		},
		applyHint(row, col) {
			state.update(($state) => {
				if (row == null || col == null) return $state;
				if ($state.puzzleGrid[row][col] !== 0) return $state;
				hints.useHint();
				$state.game.guess({
					row,
					col,
					value: $state.solvedGrid[row][col],
				});
				return { ...$state };
			});
		},
	};
}

const domainGame = createDomainGameStore();

function createGrid() {
	const gridStore = derived(domainGame, ($domainGame) => $domainGame.puzzleGrid, cloneGrid(EMPTY_GRID));
	return {
		subscribe: gridStore.subscribe,
		generate(difficulty) {
			domainGame.generate(difficulty);
		},
		decodeSencode(sencode) {
			domainGame.decodeSencode(sencode);
		},
		get(gridStoreValue, x, y) {
			return gridStoreValue[y][x];
		},
		getSencode(gridStoreValue) {
			return encodeSudoku(gridStoreValue);
		},
	};
}

function createUserGrid() {
	const userGridStore = derived(domainGame, ($domainGame) => $domainGame.game.getSudoku().getGrid(), cloneGrid(EMPTY_GRID));
	return {
		subscribe: userGridStore.subscribe,
		set(pos, value) {
			domainGame.guess(pos.y, pos.x, value);
		},
		applyHint(pos) {
			domainGame.applyHint(pos.y, pos.x);
		},
		undo() {
			domainGame.undo();
		},
		redo() {
			domainGame.redo();
		},
	};
}

export const grid = createGrid();
export const userGrid = createUserGrid();

export const invalidCells = derived(
	domainGame,
	($domainGame) => $domainGame.game.getSudoku().getInvalidCells().map((item) => {
		const [row, col] = item.split(',');
		return `${col},${row}`;
	}),
	[],
);

export const canUndo = derived(domainGame, ($domainGame) => $domainGame.game.canUndo(), false);
export const canRedo = derived(domainGame, ($domainGame) => $domainGame.game.canRedo(), false);